class ModelDownloader:
    """Downloads pretrained model checkpoints from public repositories."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.metadata_file = self.cache_dir / "download_metadata.json"
        self.metadata = self._load_metadata()

    def _load_metadata(self) -> Dict:
        if self.metadata_file.exists():
            with open(self.metadata_file, 'r') as f:
                return json.load(f)
        return {}

    def _save_metadata(self):
        with open(self.metadata_file, 'w') as f:
            json.dump(self.metadata, f, indent=2)

    def _compute_file_hash(self, filepath: Path) -> str:
        sha256 = hashlib.sha256()
        with open(filepath, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                sha256.update(chunk)
        return sha256.hexdigest()

    def download_model(self, model_name: str, force: bool = False) -> Path:
        """Download a pretrained model checkpoint from the registry."""
        if model_name not in MODEL_REGISTRY:
            raise ValueError(
                f"Model '{model_name}' not found in registry. "
                f"Available models: {list(MODEL_REGISTRY.keys())}"
            )

        model_info = MODEL_REGISTRY[model_name]
        url = model_info["url"]
        filename = f"{model_name}_{Path(url).name}"
        filepath = self.cache_dir / filename

        # Check if already downloaded
        if filepath.exists() and not force:
            logger.info(f"Model '{model_name}' already cached at {filepath}")
            return filepath

        logger.info(f"Downloading '{model_name}' from {url}...")

        # Download with progress reporting
        def _progress_hook(block_num, block_size, total_size):
            downloaded = block_num * block_size
            if total_size > 0:
                percent = min(100, downloaded * 100 / total_size)
                if block_num % 100 == 0:
                    logger.info(f"  Download progress: {percent:.1f}%")

        try:
            urllib.request.urlretrieve(url, filepath, reporthook=_progress_hook)
        except Exception as e:
            logger.error(f"Failed to download model: {e}")
            if filepath.exists():
                filepath.unlink()
            raise

        # Compute and store hash
        file_hash = self._compute_file_hash(filepath)
        self.metadata[model_name] = {
            "filepath": str(filepath),
            "url": url,
            "hash": file_hash,
            "size_mb": filepath.stat().st_size / (1024 * 1024)
        }
        self._save_metadata()

        logger.info(
            f"Downloaded '{model_name}' successfully "
            f"({self.metadata[model_name]['size_mb']:.1f} MB)"
        )
        return filepath

    def download_from_url(self, url: str, model_name: str) -> Path:
        """Download a model checkpoint from a custom URL."""
        filename = f"{model_name}_{Path(url).name}"
        filepath = self.cache_dir / filename

        if filepath.exists():
            logger.info(f"Model already cached at {filepath}")
            return filepath

        logger.info(f"Downloading from {url}...")
        try:
            urllib.request.urlretrieve(url, filepath)
        except Exception as e:
            logger.error(f"Failed to download: {e}")
            if filepath.exists():
                filepath.unlink()
            raise

        logger.info(f"Downloaded to {filepath}")
        return filepath

    def list_cached_models(self) -> Dict:
        return self.metadata


