class CheckpointLoader:
    """Loads model checkpoints using torch.load."""

    @staticmethod
    def load_checkpoint(
        filepath: str,
        device: Optional[str] = None,
        weights_only: bool = False
    ) -> Dict[str, Any]:
        """Load a model checkpoint from a file path."""
        if device is None:
            device = "cuda" if torch.cuda.is_available() else "cpu"

        logger.info(f"Loading checkpoint from {filepath} to {device}")

        checkpoint = torch.load(
            filepath,
            map_location=torch.device(device),
            weights_only=weights_only
        )

        if isinstance(checkpoint, dict):
            logger.info(f"Checkpoint keys: {list(checkpoint.keys())}")
        else:
            logger.info(f"Checkpoint type: {type(checkpoint)}")

        return checkpoint

    @staticmethod
    def load_from_url(
        url: str,
        device: Optional[str] = None,
        cache_dir: str = "./model_cache"
    ) -> Dict[str, Any]:
        """Download and load a checkpoint directly from a URL."""
        if device is None:
            device = "cuda" if torch.cuda.is_available() else "cpu"

        logger.info(f"Loading checkpoint from URL: {url}")

        checkpoint = torch.hub.load_state_dict_from_url(
            url,
            model_dir=cache_dir,
            map_location=torch.device(device)
        )

        return checkpoint

    @staticmethod
    def load_state_dict_into_model(
        model: nn.Module,
        state_dict: Dict,
        strict: bool = False
    ) -> Tuple[list, list]:
        """Load a state dict into a model with detailed mismatch reporting."""
        # Filter out mismatched keys
        model_state = model.state_dict()
        filtered_state = {}
        skipped_keys = []

        for key, value in state_dict.items():
            if key in model_state:
                if value.shape == model_state[key].shape:
                    filtered_state[key] = value
                else:
                    skipped_keys.append(
                        f"{key}: checkpoint {value.shape} vs model {model_state[key].shape}"
                    )
            else:
                skipped_keys.append(f"{key}: not in model")

        missing_keys = [k for k in model_state if k not in filtered_state]

        if skipped_keys:
            logger.warning(f"Skipped keys: {skipped_keys}")
        if missing_keys:
            logger.warning(f"Missing keys (randomly initialized): {missing_keys}")

        result = model.load_state_dict(filtered_state, strict=strict)
        logger.info("State dict loaded successfully")

        return skipped_keys, missing_keys


