class CustomImageDataset(Dataset):
    """Custom dataset for fine-tuning with image classification."""

    def __init__(
        self,
        data_dir: str,
        transform: Optional[transforms.Compose] = None,
        max_samples: Optional[int] = None
    ):
        self.data_dir = Path(data_dir)
        self.transform = transform
        self.samples = []
        self.class_to_idx = {}
        self.classes = []

        self._load_dataset(max_samples)

    def _load_dataset(self, max_samples: Optional[int] = None):
        """Load dataset from directory structure: data_dir/class_name/image.jpg"""
        if not self.data_dir.exists():
            logger.warning(f"Data directory {self.data_dir} does not exist")
            return

        class_dirs = sorted([
            d for d in self.data_dir.iterdir() if d.is_dir()
        ])

        self.classes = [d.name for d in class_dirs]
        self.class_to_idx = {cls: idx for idx, cls in enumerate(self.classes)}

        image_extensions = {'.jpg', '.jpeg', '.png', '.bmp', '.tiff', '.webp'}

        for class_dir in class_dirs:
            class_idx = self.class_to_idx[class_dir.name]
            for img_path in class_dir.iterdir():
                if img_path.suffix.lower() in image_extensions:
                    self.samples.append((str(img_path), class_idx))

        if max_samples and len(self.samples) > max_samples:
            indices = np.random.choice(len(self.samples), max_samples, replace=False)
            self.samples = [self.samples[i] for i in indices]

        logger.info(
            f"Loaded {len(self.samples)} samples across "
            f"{len(self.classes)} classes from {self.data_dir}"
        )

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        img_path, label = self.samples[idx]
        image = Image.open(img_path).convert('RGB')

        if self.transform:
            image = self.transform(image)

        return image, label


